##This code uses the tweetscores package in R to estimate ideology based on Twitter behavior.
##Complete documentation for the package is found here: https://github.com/pablobarbera/twitter_ideology
##As of November 2019, the package stopped working in a Windows environment. There have been no updates since then
##Complete information about this problem is found here: https://github.com/pablobarbera/twitter_ideology/issues/11

library(tweetscores)
user<-"BrownOfCanton"
friends <-getFriends(screen_name=user, oauth="C:/Users/mrm32/Dropbox/Journalist Audit Study/Credentials/Twitter")
results <- estimateIdeology(user, friends, method="MLE")
d21<- as.data.frame(cbind(user,mean(results$samples[,,2])))
